css:
.ps-wiki-badge { display: inline-flex; align-items: center; padding: 0.1em var(--pds-space-1); border-radius: var(--pds-radius-xs); font-size: 0.75rem; font-weight: 600; white-space: nowrap; }
.ps-wiki-badge--featured { background-color: var(--pds-status-warn); color: var(--pds-text-on-color); }
.ps-wiki-badge--good { background-color: var(--pds-status-success); color: var(--pds-text-on-color); }
.ps-wiki-badge--a-class { background-color: var(--pds-brand-blue-60); color: var(--pds-text-on-color); }
.ps-wiki-badge--b-class { background-color: var(--pds-brand-blue-50); color: var(--pds-text-on-color); }
.ps-wiki-badge--c-class, .ps-wiki-badge--stub { background-color: var(--pds-surface-layer-accent); color: var(--pds-text-secondary); }
.ps-wiki-tag { display: inline-flex; align-items: center; padding: 0.1em var(--pds-space-1); border-radius: var(--pds-radius-xs); font-size: 0.8125rem; color: var(--pds-link); border: 1px solid var(--pds-border-subtle); text-decoration: none; }
